import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Securely handling user input to prevent buffer overflow
        int maxLength = 10; // Maximum allowed length for the buffer
        char[] buffer = new char[maxLength];

        if (input.length() > maxLength) {
            System.out.println("Input exceeds maximum allowed length. Truncating...");
            input = input.substring(0, maxLength); // Truncate input if it exceeds maximum length
        }

        for (int i = 0; i < input.length(); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Input successfully stored in buffer: " + new String(buffer));
    }
}

